+func TestProfileToAgentType(t *testing.T) {
+	tests := []struct {
+		profile string
+		want    string
+	}{
+		// Claude variants
+		{"claude", "cc"},
+		{"cc", "cc"},
+		{"claude-code", "cc"},
+		{"CLAUDE", "cc"},
+		{"CC", "cc"},
+		// Codex variants
+		{"codex", "cod"},
+		{"cod", "cod"},
+		{"codex-cli", "cod"},
+		{"CODEX", "cod"},
+		// Gemini variants
+		{"gemini", "gmi"},
+		{"gmi", "gmi"},
+		{"gemini-cli", "gmi"},
+		{"GEMINI", "gmi"},
+		// Unknown profiles default to Claude
+		{"tester", "cc"},
+		{"implementer", "cc"},
+		{"explorer", "cc"},
+		{"unknown", "cc"},
+		{"", "cc"},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.profile, func(t *testing.T) {
+			got := ProfileToAgentType(tt.profile)
+			if got != tt.want {
+				t.Errorf("ProfileToAgentType(%q) = %q, want %q", tt.profile, got, tt.want)
+			}
+		})
+	}
+}
